#include<bits/stdc++.h>
using namespace std;
long long n,d[110],l[3],c[3],k[3],dp[110][1010];
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&d[i]);
    }
    scanf("%lld%lld%lld%lld%lld%lld",&l[1],&c[1],&k[1],&l[2],&c[2],&k[2]);
    memset(dp,0x3f,sizeof(dp));
    dp[0][0]=0;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=0;j<=k[1];j++)
        {
            for(long long k=0;k<=j;k++)
            {
                dp[i][j]=min(dp[i][j],dp[i-1][j-k]+max(0ll,(d[i]-l[1]*k+l[2]-1)/l[2]));
            }
        }
    }
    long long ans=LLONG_MAX;
    for(long long i=0;i<=k[1];i++)if(dp[n][i]<=k[2])
    {
        ans=min(ans,i*c[1]+dp[n][i]*c[2]);
    }
    if(ans>1e18)
    {
        ans=-1;
    }
    printf("%lld",ans);
    return 0;
}
